import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { link } from 'decantr/router';
import { Button, Avatar, Badge, icon } from 'decantr/components';

code.example:
function ConversationList({ conversations, activeId, onNew, onDelete }) {
  const { div, input, span, time, nav } = tags;
  const [search, setSearch] = createSignal('');

  const filtered = () => conversations.filter(c => 
    c.title.toLowerCase().includes(search().toLowerCase())
  );

  const grouped = () => {
    const groups = { today: [], yesterday: [], older: [] };
    const now = new Date();
    filtered().forEach(c => {
      const days = Math.floor((now - new Date(c.date)) / 86400000);
      if (days === 0) groups.today.push(c);
      else if (days === 1) groups.yesterday.push(c);
      else groups.older.push(c);
    });
    return groups;
  };

  return div({ class: css('_flex _col _hfull') },
    div({ class: css('_p3 _flex _col _gap2') },
      div({ class: css('_relative') },
        icon('search', { size: '14', class: css('_absolute _left3 _top[50%] _translate[0,-50%] _fgmuted') }),
        input({
          class: css('carbon-input _wfull _pl8'),
          placeholder: 'Search conversations...',
          value: search(),
          oninput: (e) => setSearch(e.target.value)
        })
      ),
      Button({ variant: 'outline', class: css('_wfull'), onclick: onNew },
        icon('plus'), 'New Chat'
      )
    ),
    nav({ class: css('_flex1 _overflow[auto] _px2') },
      ...Object.entries(grouped()).map(([label, items]) =>
        items.length > 0 ? div({ class: css('_mb4') },
          span({ class: css('_textsm _fgmuted _px2 _mb1 _block _capitalize') }, label),
          ...items.map(c =>
            link({
              href: `/chat/${c.id}`,
              class: css(`_flex _aic _gap2 _p2 _r2 _trans ${c.id === activeId ? '_bgmuted/10' : ''}`)
            },
              Avatar({ src: c.avatar, size: 'sm' }),
              div({ class: css('_flex1 _minw0') },
                div({ class: css('_flex _jcsb _aic') },
                  span({ class: css('_truncate _font500') }, c.title),
                  c.unread ? Badge({ size: 'xs' }, c.unread) : null
                ),
                time({ class: css('_textsm _fgmuted') }, c.lastMessage)
              )
            )
          )
        ) : null
      )
    )
  );
}

