function CompactConversationList({ conversations, activeId, onNew }) {
  const { div, nav } = tags;

  return div({ class: css('_flex _col _aic _gap2 _py2') },
    Button({ variant: 'ghost', size: 'sm', onclick: onNew, title: 'New Chat' },
      icon('plus')
    ),
    nav({ class: css('_flex _col _aic _gap1') },
      ...conversations.slice(0, 10).map(c =>
        link({
          href: `/chat/${c.id}`,
          class: css(`_p2 _r2 ${c.id === activeId ? '_bgmuted/10' : ''}`),
          title: c.title
        },
          Avatar({ src: c.avatar, size: 'sm' })
        )
      )
    )
  );
}

